import json, collections
g=json.load(open('.llm-wiki/graph.json'))
by=collections.defaultdict(list)
for n in g['nodes']:
    key=(n['type'], n['name'].lower())
    by[key].append(n)
for (typ,name),xs in sorted(by.items()):
    if len(xs)>1:
        print('DUP exact',typ,name,len(xs),[x['id'] for x in xs])
# similar arxiv ids across paper/repo/source metadata
ar=collections.defaultdict(list)
for n in g['nodes']:
    aid=n.get('metadata',{}).get('arxiv_id')
    if aid: ar[aid].append(n)
for aid,xs in sorted(ar.items()):
    if len(xs)>1:
        print('\nARXIV',aid)
        for n in xs: print(' ',n['type'],n['name'][:90],n['id'],n.get('source_path'),n.get('metadata',{}).get('title_quality'))
